// ═══════════════════════════════════════════
//  ENHANCED MARKDOWN RENDERER (with Mermaid)
// ═══════════════════════════════════════════
const MarkdownRenderer = ({ text, onHeadingsExtracted }) => {
  const headingsRef = useRef([]);
  const mermaidContainers = useRef({});
  const [mermaidReady, setMermaidReady] = useState(false);

  // Initialize mermaid
  useEffect(() => {
    const initMermaid = async () => {
      try {
        const mermaidModule = await import("mermaid");
        const mermaid = mermaidModule.default;
        mermaid.initialize({
          startOnLoad: false,
          theme: document.querySelector(".light-mode") ? "default" : "dark",
          securityLevel: "loose",
          fontFamily: "inherit",
        });
        setMermaidReady(true);
      } catch (err) {
        console.warn("Mermaid not available:", err.message);
      }
    };
    initMermaid();
  }, []);

  // Extract headings for TOC
  useEffect(() => {
    if (!text) return;
    const lines = text.split("\n");
    const headings = [];
    lines.forEach((line, idx) => {
      const match = line.match(/^(#{1,3})\s+(.+)$/);
      if (match) {
        headings.push({
          level: match[1].length,
          text: match[2].replace(/\*\*/g, "").replace(/`/g, ""),
          id: `heading-${idx}-${match[2].replace(/[^a-zA-Z0-9]/g, "-").toLowerCase()}`,
        });
      }
    });
    headingsRef.current = headings;
    if (onHeadingsExtracted) onHeadingsExtracted(headings);
  }, [text, onHeadingsExtracted]);

  if (!text) return null;

  const renderLine = (line, key) => {
    let html = line;
    // Bold
    html = html.replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>");
    // Italic
    html = html.replace(/(?<!\*)\*(?!\*)(.*?)(?<!\*)\*(?!\*)/g, "<em>$1</em>");
    // Inline Code
    html = html.replace(/`(.*?)`/g, '<code class="md-inline-code">$1</code>');
    // Links
    html = html.replace(
      /\[([^\]]+)\]\(([^)]+)\)/g,
      '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>'
    );
    // Strikethrough
    html = html.replace(/~~(.*?)~~/g, "<del>$1</del>");

    // Images
    const imgMatch = line.match(/^!\[([^\]]*)\]\(([^)]+)\)$/);
    if (imgMatch) {
      return (
        <figure key={key} className="md-figure">
          <img src={imgMatch[2]} alt={imgMatch[1]} className="md-image" loading="lazy" />
          {imgMatch[1] && <figcaption className="md-figcaption">{imgMatch[1]}</figcaption>}
        </figure>
      );
    }

    // Image credit line (italic with "Photo by")
    if (line.startsWith("*Photo by") || line.startsWith("*Image")) {
      return (
        <p key={key} className="md-image-credit" dangerouslySetInnerHTML={{ __html: html.replace(/^\*/, "").replace(/\*$/, "") }} />
      );
    }

    // Headings
    const headingMatch = line.match(/^(#{1,3})\s+(.+)$/);
    if (headingMatch) {
      const level = headingMatch[1].length;
      const content = html.replace(/^#{1,3}\s+/, "");
      const id = `heading-${key}-${headingMatch[2].replace(/[^a-zA-Z0-9]/g, "-").toLowerCase()}`;
      const Tag = `h${level}`;
      return <Tag key={key} id={id} dangerouslySetInnerHTML={{ __html: content }} />;
    }

    // Horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})$/.test(line.trim())) {
      return <hr key={key} className="md-hr" />;
    }

    // Table rows
    if (line.startsWith("|") && line.endsWith("|")) {
      const cells = line.split("|").filter(Boolean).map(c => c.trim());
      // Check if separator row
      if (cells.every(c => /^[-:]+$/.test(c))) {
        return null; // skip separator
      }
      const isHeader = key.toString().endsWith("-1") || key.toString().includes("-1-");
      return (
        <tr key={key}>
          {cells.map((cell, ci) => {
            const CellTag = isHeader ? "th" : "td";
            return <CellTag key={ci} dangerouslySetInnerHTML={{ __html: cell.replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>") }} />;
          })}
        </tr>
      );
    }

    // Unordered list
    if (/^\s*[-*+]\s/.test(line)) {
      const content = html.replace(/^\s*[-*+]\s/, "");
      return <li key={key} dangerouslySetInnerHTML={{ __html: content }} />;
    }

    // Ordered list
    if (/^\s*\d+\.\s/.test(line)) {
      const content = html.replace(/^\s*\d+\.\s/, "");
      return <li key={key} className="md-ol-item" dangerouslySetInnerHTML={{ __html: content }} />;
    }

    // Blockquote
    if (line.startsWith("> ")) {
      const content = html.substring(2);
      return <blockquote key={key} dangerouslySetInnerHTML={{ __html: content }} />;
    }

    // Empty line
    if (line.trim() === "") return <div key={key} className="md-spacer" />;

    // Regular paragraph
    return <p key={key} dangerouslySetInnerHTML={{ __html: html }} />;
  };

  // Split content by code blocks (including mermaid)
  const parts = text.split(/(```[\s\S]*?```)/g);

  return (
    <div className="md-rendered">
      {parts.map((part, partIdx) => {
        if (part.startsWith("```")) {
          const innerContent = part.slice(3, -3);
          const firstLine = innerContent.split("\n")[0]?.trim().toLowerCase();
          const codeContent = innerContent.split("\n").slice(1).join("\n");

          // Mermaid diagram
          if (firstLine === "mermaid") {
            return (
              <MermaidDiagram
                key={`mermaid-${partIdx}`}
                code={codeContent}
                mermaidReady={mermaidReady}
              />
            );
          }

          // Regular code block
          const lang = firstLine || "";
          const code = codeContent || firstLine;
          return (
            <div key={`code-${partIdx}`} className="md-code-block">
              {lang && lang !== code && <span className="md-code-lang">{lang}</span>}
              <button
                className="md-code-copy"
                onClick={() => {
                  navigator.clipboard.writeText(code);
                }}
                title="Copy code"
              >
                📋
              </button>
              <pre><code>{code}</code></pre>
            </div>
          );
        }

        // Handle tables — group table rows together
        const lines = part.split("\n");
        const rendered = [];
        let tableRows = [];
        let inTable = false;

        lines.forEach((line, lineIdx) => {
          const isTableRow = line.startsWith("|") && line.endsWith("|");
          const isSeparator = isTableRow && line.split("|").filter(Boolean).every(c => /^[\s-:]+$/.test(c));

          if (isTableRow) {
            if (!inTable) inTable = true;
            if (!isSeparator) {
              tableRows.push(renderLine(line, `${partIdx}-${lineIdx}`));
            }
          } else {
            if (inTable && tableRows.length > 0) {
              rendered.push(
                <div key={`table-wrap-${partIdx}-${lineIdx}`} className="md-table-wrapper">
                  <table className="md-table">
                    <thead>{tableRows[0]}</thead>
                    <tbody>{tableRows.slice(1)}</tbody>
                  </table>
                </div>
              );
              tableRows = [];
              inTable = false;
            }
            rendered.push(renderLine(line, `${partIdx}-${lineIdx}`));
          }
        });

        // Flush remaining table
        if (tableRows.length > 0) {
          rendered.push(
            <div key={`table-wrap-${partIdx}-end`} className="md-table-wrapper">
              <table className="md-table">
                <thead>{tableRows[0]}</thead>
                <tbody>{tableRows.slice(1)}</tbody>
              </table>
            </div>
          );
        }

        return rendered;
      })}
    </div>
  );
};

// ═══════════════════════════════════════════
//  MERMAID DIAGRAM COMPONENT
// ═══════════════════════════════════════════
const MermaidDiagram = ({ code, mermaidReady }) => {
  const containerRef = useRef(null);
  const [svgHtml, setSvgHtml] = useState("");
  const [error, setError] = useState(null);
  const [expanded, setExpanded] = useState(false);

  useEffect(() => {
    if (!mermaidReady || !code) return;

    const renderDiagram = async () => {
      try {
        const mermaidModule = await import("mermaid");
        const mermaid = mermaidModule.default;
        const id = `mermaid-blog-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`;
        const { svg } = await mermaid.render(id, code.trim());
        setSvgHtml(svg);
        setError(null);
      } catch (err) {
        console.error("Mermaid render error:", err);
        setError(err.message);
      }
    };

    renderDiagram();
  }, [code, mermaidReady]);

  if (error) {
    return (
      <div className="mermaid-error-block">
        <span>⚠️ Diagram couldn't render</span>
        <pre><code>{code}</code></pre>
      </div>
    );
  }

  return (
    <div className={`mermaid-blog-diagram ${expanded ? "expanded" : ""}`}>
      <div className="mermaid-diagram-header">
        <span>📐 Architecture Diagram</span>
        <div className="mermaid-diagram-actions">
          <button onClick={() => setExpanded(!expanded)} title={expanded ? "Collapse" : "Expand"}>
            {expanded ? "🔽" : "🔼"}
          </button>
          <button onClick={() => { navigator.clipboard.writeText(code); }} title="Copy Mermaid code">
            📋
          </button>
        </div>
      </div>
      <div className="mermaid-diagram-body" ref={containerRef}>
        {svgHtml ? (
          <div dangerouslySetInnerHTML={{ __html: svgHtml }} />
        ) : (
          <div className="mermaid-loading">
            <span className="gen-spinner" /> Rendering diagram...
          </div>
        )}
      </div>
    </div>
  );
};

const publishToExternalPlatforms = async (blogData, platforms = ["devto", "hashnode"]) => {
  try {
    const response = await fetch(`${FIREBASE_FUNCTIONS_URL}/publishBlog`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        title: blogData.title,
        content: blogData.content,
        tags: blogData.tags || [],
        slug: blogData.slug || "",
        excerpt: blogData.excerpt || "",
        platforms: platforms,
        coverImageURL: blogData.coverImageURL || null, // ← ADD THIS
      }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error || `HTTP ${response.status}`);
    }

    return await response.json();
  } catch (err) {
    console.error("External publish error:", err);
    throw err;
  }
};
// ═══════════════════════════════════════════
//  TABLE OF CONTENTS
// ═══════════════════════════════════════════
const TableOfContents = ({ headings, onNavigate }) => {
  if (!headings || headings.length === 0) return null;

  return (
    <nav className="blog-toc">
      <h4 className="toc-title">📑 Table of Contents</h4>
      <ul className="toc-list">
        {headings.map((h, i) => (
          <li
            key={i}
            className={`toc-item toc-level-${h.level}`}
            onClick={() => {
              const el = document.getElementById(h.id);
              if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
              if (onNavigate) onNavigate();
            }}
          >
            {h.text}
          </li>
        ))}
      </ul>
    </nav>
  );
};

// ═══════════════════════════════════════════
//  QUALITY SCORE BADGE
// ═══════════════════════════════════════════
const QualityBadge = ({ score }) => {
  if (!score) return null;
  const getColor = (s) => {
    if (s >= 85) return "#10b981";
    if (s >= 70) return "#f59e0b";
    return "#ef4444";
  };
  const getLabel = (s) => {
    if (s >= 85) return "Excellent";
    if (s >= 70) return "Good";
    return "Needs Work";
  };

  return (
    <div className="quality-badge" style={{ "--q-color": getColor(score) }}>
      <div className="quality-ring">
        <svg viewBox="0 0 36 36">
          <path
            className="quality-ring-bg"
            d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
          />
          <path
            className="quality-ring-fill"
            strokeDasharray={`${score}, 100`}
            d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
            style={{ stroke: getColor(score) }}
          />
        </svg>
        <span className="quality-number">{score}</span>
      </div>
      <span className="quality-label" style={{ color: getColor(score) }}>
        {getLabel(score)}
      </span>
    </div>
  );
};

// ═══════════════════════════════════════════
//  TOAST SYSTEM
// ═══════════════════════════════════════════
const useToasts = () => {
  const [toasts, setToasts] = useState([]);

  const addToast = useCallback((message, type = "info") => {
    const id = Date.now() + Math.random();
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(
      () => setToasts((prev) => prev.filter((t) => t.id !== id)),
      4000
    );
  }, []);

  const ToastContainer = () => (
    <div className="blog-toast-container" aria-live="polite">
      {toasts.map((t) => (
        <div key={t.id} className={`blog-toast blog-toast-${t.type}`}>
          <span>{t.message}</span>
          <button
            onClick={() => setToasts((p) => p.filter((x) => x.id !== t.id))}
          >
            ×
          </button>
        </div>
      ))}
    </div>
  );

  return { addToast, ToastContainer };
};

