  const [headings, setHeadings] = useState([]);
  const [showTOC, setShowTOC] = useState(false);

  // Filters
  const [filterCategory, setFilterCategory] = useState("all");
  const [filterStatus, setFilterStatus] = useState("published");
  const [searchQuery, setSearchQuery] = useState("");
  const [sortBy, setSortBy] = useState("newest");

  // UI
  const [showGenerator, setShowGenerator] = useState(false);
  const [activeGenTab, setActiveGenTab] = useState("compose"); // compose | preview | seo | export
  const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);

  // Export
  const [exportFormat, setExportFormat] = useState("markdown");

  const { addToast, ToastContainer } = useToasts();
  const modalBodyRef = useRef(null);

  const generationSteps = [
    { icon: "🧠", text: "Analyzing topic & audience..." },
    { icon: "📚", text: "Researching technical depth..." },
    { icon: "✍️", text: "Writing structured content..." },
    { icon: "🔍", text: "Optimizing for SEO..." },
    { icon: "✨", text: "Polishing & formatting..." },
  ];

  // ═══════════════════════════════════════════
  //  AUTH
  // ═══════════════════════════════════════════
  useEffect(() => {
    const auth = getAuth();
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      setCurrentUser(user);
      setIsAdmin(user?.email === ADMIN_EMAIL);
    });
    return () => unsubscribe();
  }, []);

  // ═══════════════════════════════════════════
  //  FIRESTORE LISTENER
  // ═══════════════════════════════════════════
  useEffect(() => {
    const blogsRef = collection(db, BLOG_COLLECTION);
    const q = query(blogsRef, orderBy("createdAt", "desc"));

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const newBlogs = snapshot.docs.map((d) => ({ id: d.id, ...d.data() }));
        setBlogs(newBlogs);
        setIsLoadingBlogs(false);
      },
      (error) => {
        console.error("Error fetching blogs:", error);
        setIsLoadingBlogs(false);
      }
    );

    return () => unsubscribe();
  }, []);

  // ═══════════════════════════════════════════
  //  COMPUTED / FILTERED BLOGS
  // ═══════════════════════════════════════════
  const filteredBlogs = useMemo(() => {
    let filtered = [...blogs];

    // Status filter (for public, only show published)
    if (!isAdmin) {
      filtered = filtered.filter((b) => b.status === "published" || !b.status);
    } else if (filterStatus !== "all") {
      filtered = filtered.filter(
        (b) => (b.status || "published") === filterStatus
      );
    }

    // Category filter
    if (filterCategory !== "all") {
      filtered = filtered.filter((b) => b.category === filterCategory);
    }

    // Search
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(
        (b) =>
          b.title?.toLowerCase().includes(q) ||
          b.excerpt?.toLowerCase().includes(q) ||
          b.tags?.some((t) => t.toLowerCase().includes(q))
      );
    }

    // Sort
    if (sortBy === "oldest") filtered.reverse();

    return filtered;
  }, [blogs, filterCategory, filterStatus, searchQuery, sortBy, isAdmin]);

  // ═══════════════════════════════════════════
  //  BLOG STATS
  // ═══════════════════════════════════════════
  const blogStats = useMemo(() => {
    const published = blogs.filter(
      (b) => (b.status || "published") === "published"
    ).length;
    const drafts = blogs.filter((b) => b.status === "draft").length;
    const totalWords = blogs.reduce((acc, b) => acc + (b.wordCount || 0), 0);
    return { total: blogs.length, published, drafts, totalWords };
  }, [blogs]);

  // ═══════════════════════════════════════════
  //  UTILITY FUNCTIONS
  // ═══════════════════════════════════════════
  const formatDate = (timestamp) => {
    if (!timestamp) return "Just now";
    const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
    return date.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  };

  const getReadTime = (content) => {
    if (!content) return "1 min";
    const words = content.split(/\s+/).length;
    const minutes = Math.max(1, Math.ceil(words / 250));
    return `${minutes} min read`;
  };

  const getWordCount = (content) => {
    if (!content) return 0;
    return content.split(/\s+/).filter(Boolean).length;
  };

  const generateSlug = (title) => {
    return (
      title
        ?.toLowerCase()
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/^-|-$/g, "") || "untitled"
    );
  };

  const getCategoryInfo = (catId) => {
    return BLOG_CATEGORIES.find((c) => c.id === catId) || BLOG_CATEGORIES[0];
  };
  const fetchTopicImages = async (topic, tags = []) => {
    try {
      // Generate search queries from topic and tags
      const queries = [
        topic.split(" ").slice(0, 3).join(" "), // first 3 words of topic
        ...tags.slice(0, 3),
        "software engineering",
      ].filter(Boolean).slice(0, 5);
  
      const response = await fetch(`${FIREBASE_FUNCTIONS_URL}/fetchBlogImages`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ queries }),
      });
  
      if (!response.ok) return {};
  
      const data = await response.json();
      return data.images || {};
    } catch (err) {
      console.error("Image fetch error:", err);
      return {};
    }
  };
  
  // ═══════════════════════════════════════════
  //  INJECT IMAGES INTO BLOG CONTENT
  // ═══════════════════════════════════════════
  const injectImagesIntoContent = (content, images, coverImage) => {
    if (!content) return content;
  
    const allImages = [];
    Object.values(images).forEach(imgs => {
      if (Array.isArray(imgs)) {
        imgs.forEach(img => allImages.push(img));
      }
    });
  
    if (allImages.length === 0) return content;
  
    const lines = content.split("\n");
    const result = [];
    let imageIndex = 0;
    let h2Count = 0;
  
    for (let i = 0; i < lines.length; i++) {
      result.push(lines[i]);
  
      // After every 2nd ## heading, inject an image
      if (lines[i].startsWith("## ") && !lines[i].startsWith("### ")) {
        h2Count++;
        if (h2Count % 2 === 0 && imageIndex < allImages.length) {
          const img = allImages[imageIndex];
          result.push("");
          result.push(`![${img.alt}](${img.url})`);
          result.push(`*${img.credit}*`);
          result.push("");
          imageIndex++;
        }
      }
    }
  
    return result.join("\n");
  };
  
